package genxsolution.vms.vmsbackend.maintenance_management.maintenance_assignment.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_assignment.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_assignment.service.MaintenanceAssignmentService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/maintenance-assignments") public class MaintenanceAssignmentController { private final MaintenanceAssignmentService service; public MaintenanceAssignmentController(MaintenanceAssignmentService service){this.service=service;} @GetMapping public List<MaintenanceAssignmentResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public MaintenanceAssignmentResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public MaintenanceAssignmentResponse create(@RequestBody MaintenanceAssignmentUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public MaintenanceAssignmentResponse update(@PathVariable UUID id,@RequestBody MaintenanceAssignmentUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
